#include <stdio.h>

int main() {
    int brojStola;
    char boja;

    printf("Unesite broj stola (prirodan broj): ");
    scanf("%d", &brojStola);

    printf("Unesite boju stola ('c' - crvena, 'p' - plava, 'z' - zelena): ");
    scanf(" %c", &boja);

    if (brojStola <= 0) {
        printf("Neispravan unos broja stola!\n");
    } else if (boja != 'c' && boja != 'p' && boja != 'z') {
        printf("Neispravan unos boje stola!\n");
    } else {
        printf("Za sto %d odabrana je boja: %c\n", brojStola, boja);
    }

    return 0;
}
